// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title RealEstateSale
 * @notice Simple demo contract for selling a house in Remix
 * @dev Academic/demo use only. Does not replace legal conveyancing.
 */
contract RealEstateSale {
    address public seller;
    address public buyer;

    string public propertyId;
    string public propertyAddress;
    uint256 public salePrice;
    uint256 public depositAmount;

    bool public isListed;
    bool public isReserved;
    bool public inspectionApproved;
    bool public saleCompleted;
    bool public cancelled;

    enum SaleState {
        Created,
        Listed,
        Reserved,
        Approved,
        Completed,
        Cancelled
    }

    SaleState public state;

    event PropertyListed(
        string propertyId,
        string propertyAddress,
        uint256 salePrice,
        uint256 depositAmount
    );

    event PropertyReserved(address indexed buyer, uint256 depositPaid);
    event InspectionApproved(address indexed seller);
    event BalancePaid(address indexed buyer, uint256 amount);
    event SaleCompleted(address indexed seller, address indexed buyer, uint256 totalPaid);
    event SaleCancelled(address indexed seller, address indexed buyer, uint256 refundedAmount);

    modifier onlySeller() {
        require(msg.sender == seller, "Only seller can call this");
        _;
    }

    modifier onlyBuyer() {
        require(msg.sender == buyer, "Only buyer can call this");
        _;
    }

    modifier notCompleted() {
        require(!saleCompleted, "Sale already completed");
        _;
    }

    modifier notCancelled() {
        require(!cancelled, "Sale cancelled");
        _;
    }

    constructor() {
        seller = msg.sender;
        state = SaleState.Created;
    }

    /**
     * @notice Seller lists the property for sale
     */
    function listProperty(
        string memory _propertyId,
        string memory _propertyAddress,
        uint256 _salePrice,
        uint256 _depositAmount
    ) external onlySeller notCompleted notCancelled {
        require(!isListed, "Property already listed");
        require(_salePrice > 0, "Sale price must be greater than zero");
        require(_depositAmount > 0, "Deposit must be greater than zero");
        require(_depositAmount < _salePrice, "Deposit must be less than sale price");

        propertyId = _propertyId;
        propertyAddress = _propertyAddress;
        salePrice = _salePrice;
        depositAmount = _depositAmount;

        isListed = true;
        state = SaleState.Listed;

        emit PropertyListed(_propertyId, _propertyAddress, _salePrice, _depositAmount);
    }

    /**
     * @notice Buyer reserves the property by paying the deposit
     */
    function reserveProperty() external payable notCompleted notCancelled {
        require(isListed, "Property not listed");
        require(!isReserved, "Property already reserved");
        require(msg.value == depositAmount, "Incorrect deposit amount");

        buyer = msg.sender;
        isReserved = true;
        state = SaleState.Reserved;

        emit PropertyReserved(msg.sender, msg.value);
    }

    /**
     * @notice Seller approves inspection / confirms deal can proceed
     */
    function approveInspection() external onlySeller notCompleted notCancelled {
        require(isReserved, "Property not reserved");
        require(!inspectionApproved, "Inspection already approved");

        inspectionApproved = true;
        state = SaleState.Approved;

        emit InspectionApproved(msg.sender);
    }

    /**
     * @notice Buyer pays the remaining balance after approval
     */
    function payRemainingBalance() external payable onlyBuyer notCompleted notCancelled {
        require(isReserved, "Property not reserved");
        require(inspectionApproved, "Inspection not approved");

        uint256 requiredRemaining = salePrice - depositAmount;
        require(msg.value == requiredRemaining, "Incorrect remaining balance");

        emit BalancePaid(msg.sender, msg.value);
    }

    /**
     * @notice Seller finalizes the sale and receives all funds
     */
    function finalizeSale() external onlySeller notCompleted notCancelled {
        require(isReserved, "Property not reserved");
        require(inspectionApproved, "Inspection not approved");
        require(address(this).balance == salePrice, "Full payment not yet received");

        saleCompleted = true;
        state = SaleState.Completed;

        uint256 totalPaid = address(this).balance;
        payable(seller).transfer(totalPaid);

        emit SaleCompleted(seller, buyer, totalPaid);
    }

    /**
     * @notice Seller can cancel before completion
     * @dev If buyer already paid deposit/balance, funds are refunded to buyer
     */
    function cancelSale() external onlySeller notCompleted notCancelled {
        cancelled = true;
        state = SaleState.Cancelled;

        uint256 refundAmount = address(this).balance;

        if (refundAmount > 0 && buyer != address(0)) {
            payable(buyer).transfer(refundAmount);
        }

        emit SaleCancelled(seller, buyer, refundAmount);
    }

    /**
     * @notice View contract balance
     */
    function getContractBalance() external view returns (uint256) {
        return address(this).balance;
    }

    /**
     * @notice Simple ownership view for demo purposes
     * @dev Before completion, seller is treated as owner; after completion, buyer is treated as owner
     */
    function currentOwner() external view returns (address) {
        if (saleCompleted) {
            return buyer;
        }
        return seller;
    }
}

